// Parse event data from webhook body
const body = $input.first().json.body || $input.first().json;
const event_id = body.event_id || '';
const project_id = body.project_id || '';
const event_type = body.event_type || 'SCHEDULE_GENERATED';
const payload = body.payload || {};

return [{ json: { event_id, project_id, event_type, payload } }];

const data = $input.first().json;
const projectId = $('Parse Event Data').first().json.project_id;
const phases = typeof data.phases === 'string' ? JSON.parse(data.phases) : data.phases;

// Format dates
function fmtDate(d) {
  if (!d) return '?';
  const dt = new Date(d);
  return `${String(dt.getDate()).padStart(2,'0')}.${String(dt.getMonth()+1).padStart(2,'0')}.`;
}

let lines = [];
lines.push(`📅 <b>Zeitplan generiert</b>`);
lines.push(`<b>${data.project_number}</b> — ${data.address}`);
lines.push('');
lines.push(`<b>Gewerke:</b>`);

if (phases && phases.length > 0) {
  for (const p of phases) {
    const initial = p.team_member ? p.team_member.split(' ').map(n => n[0]).join('.') + '.' : '?';
    lines.push(`${p.phase_number}. ${p.trade}: ${fmtDate(p.start_date)} – ${fmtDate(p.end_date)} (${p.team_member})`);
  }
} else {
  lines.push('Keine Phasen vorhanden.');
}

lines.push('');
lines.push(`Zeitraum: ${fmtDate(data.planned_start)} – ${fmtDate(data.planned_end)}${data.planned_end ? new Date(data.planned_end).getFullYear() : ''}`);

const text = lines.join('\n');

// Build approval URL
const approveUrl = `https://n8n.srv1045913.hstgr.cloud/webhook/m2-10-schedule-approve?project_id=${projectId}&action=approve`;
const rejectUrl = `https://n8n.srv1045913.hstgr.cloud/webhook/m2-10-schedule-approve?project_id=${projectId}&action=reject`;

return [{ json: { text, approveUrl, rejectUrl, projectId, project_number: data.project_number } }];

